7	const MAIN_ITEM_PREMIUMS: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	};
13	
14	function isComponent(type: string): boolean {
15	  return !(type in MAIN_ITEM_PREMIUMS);
16	}
