18	function computeComponentPremium(items: any[]): number {
19	  const componentCounts: Record<string, number> = {};
20	
21	  for (const item of items) {
22	    if (isComponent(item.type)) {
23	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
24	    }
25	  }
26	
27	  let premium = 0;
28	  for (const count of Object.values(componentCounts)) {
29	    premium += count === COMPONENT_BLOCK_SIZE
30	      ? COMPONENT_BLOCK_PREMIUM
31	      : count * COMPONENT_PREMIUM;
32	  }
33	  return premium;
34	}
35	
36	function computeMainItemPremium(items: any[]): number {
37	  let premium = 0;
38	  for (const item of items) {
39	    if (!isComponent(item.type)) {
40	      let itemPremium = MAIN_ITEM_PREMIUMS[item.type];
41	      if (item.cursed) {
42	        itemPremium += itemPremium * CURSED_SURCHARGE_RATE;
43	      }
44	      if (item.enchantment >= 5) {
45	        itemPremium += MAIN_ITEM_PREMIUMS[item.type] * 0.3;
46	      }
47	      premium += itemPremium;
48	    }
49	  }
50	  return premium;
51	}
52	
53	function computeBasePremium(items: any[]): number {
54	  return computeMainItemPremium(items) + computeComponentPremium(items);
55	}
